  function switchLanguage(lang) {
    localStorage.setItem('language', lang);
    applyLanguage(lang);
    
    // Dispatch language changed event
    window.dispatchEvent(new CustomEvent('languageChanged', {
      detail: { lang }
    }));
  }
  
  // Make switchLanguage available globally
  window.switchLanguage = switchLanguage;
  
  function applyLanguage(lang) {
    const elements = document.querySelectorAll('[data-translate]');
    elements.forEach((el) => {
      const key = el.getAttribute('data-translate');
      if (translations[lang][key]) {
        el.innerHTML = translations[lang][key];
      }
    });
  
    const heroTitle = document.querySelector('.hero h1');
    const heroSubtitle = document.querySelector('.hero .subtitle');
    const heroCTA = document.querySelector('.hero .cta-btn');
    if (heroTitle) heroTitle.innerHTML = translations[lang].heroTitle;
    if (heroSubtitle) heroSubtitle.innerHTML = translations[lang].heroSubtitle;
    if (heroCTA) heroCTA.innerHTML = translations[lang].heroCTA;
  
    const newsletterTitle = document.querySelector('.cta-section h2');
    const newsletterSub = document.querySelector('.cta-section p');
    if (newsletterTitle) newsletterTitle.innerHTML = translations[lang].newsletterHeading;
    if (newsletterSub) newsletterSub.innerHTML = translations[lang].newsletterSub;
  
    const featureHeading = document.querySelector('.features-wrapper h2');
    const featureIntro = document.querySelector('.features-wrapper .intro');
    if (featureHeading) featureHeading.innerHTML = translations[lang].featureTitle;
    if (featureIntro) featureIntro.innerHTML = translations[lang].featureIntro;
  
    document.querySelectorAll('.feature-card').forEach((card, index) => {
      const title = card.querySelector('h3');
      const desc = card.querySelector('p');
      // Only apply automatic translations if elements don't have data-translate attribute
      if (title && !title.hasAttribute('data-translate')) {
        title.innerHTML = translations[lang][`feature${index + 1}Title`];
      }
      if (desc && !desc.hasAttribute('data-translate')) {
        desc.innerHTML = translations[lang][`feature${index + 1}Desc`];
      }
    });
  
    const footer = {
      contact: document.querySelector('h4[data-translate="footerContact"]'),
      address: document.querySelector('h4[data-translate="footerAddress"]'),
      social: document.querySelector('h4[data-translate="footerSocial"]'),
      email: document.querySelector('p[data-translate="footerEmail"]'),
      phone: document.querySelector('p[data-translate="footerPhone"]'),
      company: document.querySelector('p[data-translate="footerCompany"]'),
      street: document.querySelector('p[data-translate="footerStreet"]'),
      city: document.querySelector('p[data-translate="footerCity"]'),
      facebook: document.querySelector('a[data-translate="footerFacebook"]'),
      instagram: document.querySelector('a[data-translate="footerInstagram"]'),
      tiktok: document.querySelector('a[data-translate="footerTiktok"]')
    };
  
    Object.entries(footer).forEach(([key, el]) => {
      if (el && translations[lang][`footer${key.charAt(0).toUpperCase() + key.slice(1)}`]) {
        el.innerHTML = translations[lang][`footer${key.charAt(0).toUpperCase() + key.slice(1)}`];
      }
    });

    // Update popup content
    const popupTitle = document.querySelector('#newsletterModal h3');
    const popupEmail = document.querySelector('#newsletterModal input[type="email"]');
    const popupPhone = document.querySelector('#newsletterModal input[type="tel"]');
    const popupSubmit = document.querySelector('#newsletterModal .submit-btn');
    const popupDecline = document.querySelector('#newsletterModal .decline-btn');
    const popupDisclaimer = document.querySelector('#newsletterModal .disclaimer');
    const confirmationTitle = document.querySelector('#confirmationPopup h3');
    const confirmationText = document.querySelector('#confirmationPopup p');
    const confirmationClose = document.querySelector('#confirmationPopup .submit-btn');

    if (popupTitle) popupTitle.innerHTML = translations[lang].popupTitle;
    if (popupEmail) popupEmail.placeholder = translations[lang].popupEmailPlaceholder;
    if (popupPhone) popupPhone.placeholder = translations[lang].popupPhonePlaceholder;
    if (popupSubmit) popupSubmit.innerHTML = translations[lang].popupSubmit;
    if (popupDecline) popupDecline.innerHTML = translations[lang].popupDecline;
    if (popupDisclaimer) popupDisclaimer.innerHTML = translations[lang].popupDisclaimer;
    if (confirmationTitle) confirmationTitle.innerHTML = translations[lang].confirmationTitle;
    if (confirmationText) confirmationText.innerHTML = translations[lang].confirmationText;
    if (confirmationClose) confirmationClose.innerHTML = translations[lang].confirmationClose;

    // Update hero top text
    const heroTopText = document.querySelector('.small-top-text');
    if (heroTopText) {
      heroTopText.innerHTML = translations[lang].heroTopText + 
        '<span class="highlight-text">' + 
        translations[lang].heroHighlightText + 
        ' <span class="arrow">➔</span></span>';
    }

    // Update close button
    const closeButton = document.querySelector('.close-btn');
    if (closeButton) {
      closeButton.innerHTML = translations[lang].closeButton;
    }

    // Update country options
    const countryOptions = document.querySelectorAll('#countrySelect option');
    countryOptions.forEach(option => {
      const countryCode = option.value.toUpperCase();
      if (translations[lang][`country${countryCode}`]) {
        option.innerHTML = translations[lang][`country${countryCode}`];
      }
    });
  }
  
  document.addEventListener('DOMContentLoaded', () => {
    const savedLang = localStorage.getItem('language') || 'sv';
    applyLanguage(savedLang);
  });